always @(posedge clock) begin
  if (reset) begin
    io_intt_validout <= 1'b0;
    io_ntt_validout <= 1'b0;
    intt_in_count <= 4'd0;
    ntt_in_count <= 4'd0;
    intt_out_count <= 4'd0;
    ntt_out_count <= 4'd0;
    intt_output_active <= 1'b0;
    ntt_output_active <= 1'b0;
    for (i = 0; i < YATA_N; i = i + 1) begin
      intt_in_buf[i] <= 32'd0;
      intt_out_buf[i] <= 27'sd0;
      ntt_in_buf[i] <= 27'sd0;
      ntt_out_buf[i] <= 32'd0;
    end
  end else begin
    io_intt_validout <= 1'b0;
    io_ntt_validout <= 1'b0;

    if (intt_output_active) begin
      io_intt_validout <= 1'b1;
        io_intt_out_0 <= intt_out_buf[intt_out_count * 8 + 0];
        io_intt_out_1 <= intt_out_buf[intt_out_count * 8 + 1];
        io_intt_out_2 <= intt_out_buf[intt_out_count * 8 + 2];
        io_intt_out_3 <= intt_out_buf[intt_out_count * 8 + 3];
        io_intt_out_4 <= intt_out_buf[intt_out_count * 8 + 4];
        io_intt_out_5 <= intt_out_buf[intt_out_count * 8 + 5];
        io_intt_out_6 <= intt_out_buf[intt_out_count * 8 + 6];
        io_intt_out_7 <= intt_out_buf[intt_out_count * 8 + 7];
  if (intt_out_count == YATA_CYCLES - 1) begin
    intt_output_active <= 1'b0;
    intt_out_count <= 4'd0;
  end else begin
    intt_out_count <= intt_out_count + 1'b1;
  end
end

if (ntt_output_active) begin
  io_ntt_validout <= 1'b1;
        io_ntt_out_0 <= ntt_out_buf[0 * YATA_CYCLES + ntt_out_count];
        io_ntt_out_1 <= ntt_out_buf[1 * YATA_CYCLES + ntt_out_count];
        io_ntt_out_2 <= ntt_out_buf[2 * YATA_CYCLES + ntt_out_count];
        io_ntt_out_3 <= ntt_out_buf[3 * YATA_CYCLES + ntt_out_count];
        io_ntt_out_4 <= ntt_out_buf[4 * YATA_CYCLES + ntt_out_count];
        io_ntt_out_5 <= ntt_out_buf[5 * YATA_CYCLES + ntt_out_count];
        io_ntt_out_6 <= ntt_out_buf[6 * YATA_CYCLES + ntt_out_count];
        io_ntt_out_7 <= ntt_out_buf[7 * YATA_CYCLES + ntt_out_count];
  if (ntt_out_count == YATA_CYCLES - 1) begin
    ntt_output_active <= 1'b0;
    ntt_out_count <= 4'd0;
  end else begin
    ntt_out_count <= ntt_out_count + 1'b1;
  end
end

if (io_intt_validin) begin
        intt_in_buf[0 * YATA_CYCLES + intt_in_count] = io_intt_in_0;
        intt_in_buf[1 * YATA_CYCLES + intt_in_count] = io_intt_in_1;
        intt_in_buf[2 * YATA_CYCLES + intt_in_count] = io_intt_in_2;
        intt_in_buf[3 * YATA_CYCLES + intt_in_count] = io_intt_in_3;
        intt_in_buf[4 * YATA_CYCLES + intt_in_count] = io_intt_in_4;
        intt_in_buf[5 * YATA_CYCLES + intt_in_count] = io_intt_in_5;
        intt_in_buf[6 * YATA_CYCLES + intt_in_count] = io_intt_in_6;
        intt_in_buf[7 * YATA_CYCLES + intt_in_count] = io_intt_in_7;
  if (intt_in_count == YATA_CYCLES - 1) begin
    intt_in_count <= 4'd0;
    compute_intt();
    intt_output_active <= 1'b1;
    intt_out_count <= 4'd0;
  end else begin
    intt_in_count <= intt_in_count + 1'b1;
  end
end

if (io_ntt_validin) begin
        ntt_in_buf[ntt_in_count * 8 + 0] = io_ntt_in_0;
        ntt_in_buf[ntt_in_count * 8 + 1] = io_ntt_in_1;
        ntt_in_buf[ntt_in_count * 8 + 2] = io_ntt_in_2;
        ntt_in_buf[ntt_in_count * 8 + 3] = io_ntt_in_3;
        ntt_in_buf[ntt_in_count * 8 + 4] = io_ntt_in_4;
        ntt_in_buf[ntt_in_count * 8 + 5] = io_ntt_in_5;
        ntt_in_buf[ntt_in_count * 8 + 6] = io_ntt_in_6;
        ntt_in_buf[ntt_in_count * 8 + 7] = io_ntt_in_7;
        if (ntt_in_count == YATA_CYCLES - 1) begin
          ntt_in_count <= 4'd0;
          compute_ntt();
          ntt_output_active <= 1'b1;
          ntt_out_count <= 4'd0;
        end else begin
          ntt_in_count <= ntt_in_count + 1'b1;
        end
      end
    end
  end
